func TestMove_MissingNeighborID_FallsBackToEndOfColumn(t *testing.T) {
	repo, pool, _ := newTestRepository(t)
	ctx := context.Background()

	require.NoError(t, insertRawBookmarkAt(ctx, pool, testUUID(1), "hash-1", "reading", "b"))
	require.NoError(t, insertRawBookmarkAt(ctx, pool, testUUID(2), "hash-2", "reading", "d"))

	moving, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/moving"})
	require.NoError(t, err)

	stale := domain.BookmarkID(testUUID(99)) // never inserted — deleted-between-drag-and-drop stand-in
	_, err = repo.Move(ctx, adapter.MoveCommand{
		ID:           moving.ID,
		TargetStatus: domain.StatusReading,
		Before:       &stale,
	})
	require.NoError(t, err, "a missing/stale neighbor ID must fall back to end-of-column, not fail the request")

	board, err := repo.Board(ctx, adapter.BoardFilter{})
	require.NoError(t, err)
	require.Len(t, board.Reading, 3)
	assert.Equal(t, domain.BookmarkID(testUUID(1)), board.Reading[0].ID, "existing neighbors' relative order must be untouched")
	assert.Equal(t, domain.BookmarkID(testUUID(2)), board.Reading[1].ID)
	assert.Equal(t, moving.ID, board.Reading[2].ID, "moved bookmark must land last (end-of-column) in the target column")
}

