// from interview: Q4
func TestMove_BeforeAndAfterBothSet_BeforeWins(t *testing.T) {
	repo, pool, _ := newTestRepository(t)
	ctx := context.Background()

	cardA := domain.BookmarkID(testUUID(1))
	cardB := domain.BookmarkID(testUUID(2))
	cardC := domain.BookmarkID(testUUID(3))
	require.NoError(t, insertRawBookmarkAt(ctx, pool, string(cardA), "hash-a", "reading", "b"))
	require.NoError(t, insertRawBookmarkAt(ctx, pool, string(cardB), "hash-b", "reading", "d"))
	require.NoError(t, insertRawBookmarkAt(ctx, pool, string(cardC), "hash-c", "reading", "f"))

	moving, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/moving"})
	require.NoError(t, err)

	// Before=cardB says "insert right after B, before C". After=cardA
	// disagrees ("insert right before A" — the front). Before must win.
	_, err = repo.Move(ctx, adapter.MoveCommand{
		ID:           moving.ID,
		TargetStatus: domain.StatusReading,
		Before:       &cardB,
		After:        &cardA,
	})
	require.NoError(t, err)

	board, err := repo.Board(ctx, adapter.BoardFilter{})
	require.NoError(t, err)
	require.Len(t, board.Reading, 4)
	gotOrder := []domain.BookmarkID{board.Reading[0].ID, board.Reading[1].ID, board.Reading[2].ID, board.Reading[3].ID}
	assert.Equal(t, []domain.BookmarkID{cardA, cardB, moving.ID, cardC}, gotOrder,
		"Before must take precedence — the moved card lands between B and C, and the disagreeing After=A instruction is ignored outright")
}

