// from interview: Q5 — the adversarial case: an advanceable clock is
// required to distinguish "preserved" from "re-stamped to the same
// instant," which a single fixed clock cannot express.
func TestMove_DoneToDone_PreservesFinishedAtButBumpsUpdatedAt(t *testing.T) {
	pool := newTestPool(t)
	ctx := context.Background()

	t1 := time.Date(2026, 7, 13, 9, 0, 0, 0, time.UTC)
	clock := newMutableClock(t1)
	repo := postgres.New(pool, clock.Now)

	moving, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/a"})
	require.NoError(t, err)

	enteredDone, err := repo.Move(ctx, adapter.MoveCommand{ID: moving.ID, TargetStatus: domain.StatusDone})
	require.NoError(t, err)
	require.NotNil(t, enteredDone.FinishedAt)
	assert.True(t, enteredDone.FinishedAt.Equal(t1))

	t2 := t1.Add(3 * time.Hour)
	clock.Advance(3 * time.Hour)

	// Same-column reorder within Done — TargetStatus is Done again, and
	// the bookmark's current Status is already Done.
	reordered, err := repo.Move(ctx, adapter.MoveCommand{ID: moving.ID, TargetStatus: domain.StatusDone})
	require.NoError(t, err)
	require.NotNil(t, reordered.FinishedAt)
	assert.True(t, reordered.FinishedAt.Equal(t1), "a Done->Done reorder must PRESERVE the original FinishedAt, not re-stamp it to the new clock instant")
	assert.True(t, reordered.UpdatedAt.Equal(t2), "UpdatedAt must still bump to the new clock instant even though FinishedAt is preserved")
}

