// from interview: Q2, Q3 — black-box stress test for the fractional-rank
// algorithm's length-extension behavior: repeatedly inserting into the
// same narrowing gap must never produce a duplicate or out-of-order
// Position. Tests assert the ordering invariant only, never a literal
// rank string (Q2).
func TestMove_RepeatedInsertsIntoSameGap_MaintainsStrictOrder(t *testing.T) {
	repo, pool, _ := newTestRepository(t)
	ctx := context.Background()

	lowID := domain.BookmarkID(testUUID(1))
	highID := domain.BookmarkID(testUUID(2))
	require.NoError(t, insertRawBookmarkAt(ctx, pool, string(lowID), "hash-low", "reading", "b"))
	require.NoError(t, insertRawBookmarkAt(ctx, pool, string(highID), "hash-high", "reading", "z"))

	const n = 12
	predecessor := lowID
	for i := 0; i < n; i++ {
		card, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: fmt.Sprintf("https://example.com/gap-%d", i)})
		require.NoError(t, err)

		pred, succ := predecessor, highID
		_, err = repo.Move(ctx, adapter.MoveCommand{
			ID:           card.ID,
			TargetStatus: domain.StatusReading,
			Before:       &pred,
			After:        &succ,
		})
		require.NoError(t, err, "insert %d into the narrowing gap must succeed without exhausting rank precision", i)
		predecessor = card.ID
	}

	board, err := repo.Board(ctx, adapter.BoardFilter{})
	require.NoError(t, err)
	require.Len(t, board.Reading, n+2)

	for i := 1; i < len(board.Reading); i++ {
		assert.Less(t, string(board.Reading[i-1].Position), string(board.Reading[i].Position),
			"Position must be strictly increasing across every row in the column — a repeated narrow-gap insert must never produce a duplicate or out-of-order rank")
	}
	assert.Equal(t, lowID, board.Reading[0].ID)
	assert.Equal(t, highID, board.Reading[len(board.Reading)-1].ID)
}

// --- Position collision / Decision B (interview Q3, Q7, Q12) -----------

// from interview: Q7 — the livelock guard: the loser must re-resolve
// neighbor adjacency and retry, not reuse stale ranks and recompute the
// same colliding midpoint forever.
func TestMove_ConcurrentSameGapMoves_BothSucceedDistinctRanksCorrectOrder(t *testing.T) {
	repo, pool, _ := newTestRepository(t)
	ctx := context.Background()

	lowID := domain.BookmarkID(testUUID(1))
	highID := domain.BookmarkID(testUUID(2))
	require.NoError(t, insertRawBookmarkAt(ctx, pool, string(lowID), "hash-low", "reading", "b"))
	require.NoError(t, insertRawBookmarkAt(ctx, pool, string(highID), "hash-high", "reading", "z"))

	cardA, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/card-a"})
	require.NoError(t, err)
	cardB, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/card-b"})
	require.NoError(t, err)

	var wg sync.WaitGroup
	errs := make([]error, 2)
	low, high := lowID, highID
	wg.Add(2)
	go func() {
		defer wg.Done()
		_, errs[0] = repo.Move(ctx, adapter.MoveCommand{ID: cardA.ID, TargetStatus: domain.StatusReading, Before: &low, After: &high})
	}()
	go func() {
		defer wg.Done()
		_, errs[1] = repo.Move(ctx, adapter.MoveCommand{ID: cardB.ID, TargetStatus: domain.StatusReading, Before: &low, After: &high})
	}()
	wg.Wait()

	require.NoError(t, errs[0], "both movers into the same gap must eventually succeed — the loser must re-resolve neighbor adjacency and retry, not fail the request")
	require.NoError(t, errs[1])

	board, err := repo.Board(ctx, adapter.BoardFilter{})
	require.NoError(t, err)
	require.Len(t, board.Reading, 4)

	positions := make(map[domain.BookmarkID]int, 4)
	for i, b := range board.Reading {
		positions[b.ID] = i
	}
	assert.Equal(t, 0, positions[lowID], "low must remain first")
	assert.Equal(t, 3, positions[highID], "high must remain last")
	assert.NotEqual(t, positions[cardA.ID], positions[cardB.ID], "the two concurrently-moved cards must land at distinct positions, not a collided/duplicate rank")
	for i := 1; i < len(board.Reading); i++ {
		assert.Less(t, string(board.Reading[i-1].Position), string(board.Reading[i].Position), "final order must be a strict byte-order chain — no duplicate or out-of-order Position")
	}
}

