// --- Board snapshot consistency (interview Q8) --------------------------

// from interview: Q8 — a deterministic controlled-transaction test, not
// a goroutine race: a raw in-flight UPDATE stands in for a paused Move
// since this tests Board's read-snapshot consistency, which is
// writer-agnostic.
func TestBoard_DuringInFlightMoveTransaction_SnapshotConsistent(t *testing.T) {
	repo, pool, _ := newTestRepository(t)
	ctx := context.Background()

	moving, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/a"})
	require.NoError(t, err)

	tx, err := pool.Begin(ctx)
	require.NoError(t, err)

	_, err = tx.Exec(ctx, "UPDATE bookmarks SET status = 'reading' WHERE id = $1", string(moving.ID))
	require.NoError(t, err)

	boardDuring, err := repo.Board(ctx, adapter.BoardFilter{})
	require.NoError(t, err, "Board must not block on or error against an in-flight uncommitted writer")
	require.Len(t, boardDuring.Inbox, 1, "Board must see the pre-transaction committed state — the uncommitted UPDATE must be invisible")
	assert.Empty(t, boardDuring.Reading)
	assert.Equal(t, moving.ID, boardDuring.Inbox[0].ID)

	require.NoError(t, tx.Commit(ctx))

	boardAfter, err := repo.Board(ctx, adapter.BoardFilter{})
	require.NoError(t, err)
	require.Len(t, boardAfter.Reading, 1, "after commit, Board must see the new column")
	assert.Empty(t, boardAfter.Inbox)
	assert.Equal(t, moving.ID, boardAfter.Reading[0].ID)
}

// --- Partial-failure / commit-boundary contract (interview Q9, Q10) ----

// from interview: Q10 — pre-commit failure must leave the row completely
// unchanged (mirrors Create's contract from issue #2).
func TestMove_ContextCanceledBeforeCommit_RowUnchanged(t *testing.T) {
	repo, pool, _ := newTestRepository(t)

	moving, err := repo.Create(context.Background(), domain.NewBookmark{OriginalURL: "https://example.com/a"})
	require.NoError(t, err)

	canceled, cancel := context.WithCancel(context.Background())
	cancel()

	_, err = repo.Move(canceled, adapter.MoveCommand{ID: moving.ID, TargetStatus: domain.StatusDone})
	require.Error(t, err, "Move called with an already-canceled context must fail before any write lands")

	var (
		status     string
		position   string
		finishedAt *time.Time
	)
	require.NoError(t, pool.QueryRow(context.Background(), "SELECT status, position, finished_at FROM bookmarks WHERE id = $1", string(moving.ID)).
		Scan(&status, &position, &finishedAt))
	assert.Equal(t, string(domain.StatusInbox), status, "a pre-commit failure must leave status completely unchanged")
	assert.Equal(t, string(moving.Position), position, "a pre-commit failure must leave position completely unchanged")
	assert.Nil(t, finishedAt, "a pre-commit failure must not have set finished_at")
}

// --- E1 defense-in-depth (interview Q1) ---------------------------------

// from interview: Q1 — the one defensive test this issue owns for E1;
// the 400-rejection behavior itself belongs to issue #5.
func TestMove_InvalidTargetStatus_FailsCleanlyViaCheckConstraint(t *testing.T) {
	repo, pool, _ := newTestRepository(t)
	ctx := context.Background()

	moving, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/a"})
	require.NoError(t, err)

	_, err = repo.Move(ctx, adapter.MoveCommand{ID: moving.ID, TargetStatus: domain.Status("bogus")})
	require.Error(t, err, `a garbage TargetStatus that somehow reaches Move must fail cleanly, not corrupt the row — internal/api (issue #5) is responsible for rejecting this before Move is ever called (DECISIONS.md "MoveCommand.TargetStatus — Validation Ownership (E1, resolved)")`)

	var repoErr *adapter.RepositoryError
	assert.False(t, errors.As(err, &repoErr), "a CHECK-constraint failure must surface as a plain infrastructure error, not a classified *adapter.RepositoryError")

	var status string
	require.NoError(t, pool.QueryRow(ctx, "SELECT status FROM bookmarks WHERE id = $1", string(moving.ID)).Scan(&status))
	assert.Equal(t, string(domain.StatusInbox), status, "the row must be completely unchanged after a rejected garbage status")
}
